mapper.select:
SELECT a.TMPLET_ID , b.SUB_KEY , b.SUB_VAL_TYP_CD , d.CD_NM AS SUB_VAL_TYP_NM , c.SUB_VAL , b.SUB_EXPL , b.SUB_VAL_SEQ , c.SYNC_SUB_VAL FROM PM_TMPLET_MST a, PM_TMPLET_SUBKEY_MAP b, PM_TMPLET_SUBVAL_MAP c, (SELECT * FROM AD_COMM_CD WHERE COMM_GRP_CD = 'SUB_VAL_TYP_CD') d WHERE 1=1 AND a.TMPLET_ID = b.TMPLET_ID AND b.TMPLET_ID = c.TMPLET_ID(+) AND b.SUB_KEY = c.SUB_KEY(+) AND b.SUB_VAL_SEQ = c.SUB_VAL_SEQ(+) AND b.SUB_VAL_TYP_CD = d.COMM_CD AND a.TMPLET_ID = #{tmpletId} AND b.USE_YN = 'Y'
AND b.SUB_KEY = #{subKey}
ORDER BY SUB_KEY
